@pytest.fixture(scope="session")
def app(settings):  # settings is function-scoped — pytest will error
    return create_app(settings)

@pytest.fixture
def make_user(db):
    def factory(email="user@example.com", role="user", **kwargs):
        return User.objects.create(email=email, role=role, **kwargs)
    return factory

def test_admin_access(make_user):
    admin = make_user(role="admin")
    assert admin.can_access_admin_panel()

@pytest.fixture(autouse=True)
def reset_cache():
    """Auto-clear in-memory cache before each test to prevent state leakage."""
    cache.clear()
    yield
    cache.clear()

