@pytest.mark.parametrize("email,valid", [
    ("user@example.com", True),
    ("invalid-email", False),
    ("@nodomain.com", False),
    ("user@.com", False),
], ids=["valid", "no-at", "no-local", "no-tld"])
def test_email_validation(email, valid):
    assert validate_email(email) == valid

def test_send_welcome_email(mocker, make_user): mock_send = mocker.patch("myapp.services.email.send_email") user = make_user(email="new@example.com")
send_welcome_email(user)
